                {"speaker": "You", "swissGerman": "Okay, ich chume! Wo isch de Sammelplatz?", "german": "Okay, ich komme! Wo ist der Sammelplatz?", "english": "Okay, I'm coming! Where's the assembly point?", "spanish": "¡Bien, ya voy! ¿Dónde está el punto de encuentro?"},
                {"speaker": "Neighbor", "swissGerman": "Vor em Hüsli, bim Briefkaschte. Dä ischs uf em Schild oene beschriibe.", "german": "Vor dem Haus, beim Briefkasten. Das ist auf dem Schild draussen beschrieben.", "english": "In front of the building, by the mailbox. It's described on the sign outside.", "spanish": "Delante del edificio, junto al buzón. Está descrito en el cartel de fuera."},
                {"speaker": "You", "swissGerman": "Okay danke! Ich chume jetzt. Hop hop!", "german": "Okay danke! Ich komme jetzt. Schnell schnell!", "english": "Okay thanks! I'm coming now. Quick quick!", "spanish": "¡Bien, gracias! Ya voy. ¡Rápido rápido!"},
